SELECT workclass, industry
FROM workclass
WHERE workclass = 'Private' AND fnlwgt > 100000;

SELECT occupation, job_title
FROM occupation
WHERE job_level = 'Mid-level';

SELECT DISTINCT race 
FROM demographics 
ORDER BY race;

SELECT COUNT(id) AS number_of_individuals
FROM income
WHERE income_source = 'Self-employment';

SELECT COUNT(id) AS full_time_employees
FROM hours_per_week
WHERE job_type = 'Full-time';

SELECT COUNT(*) 
FROM marital_status
WHERE marital_status = 'Married-civ-spouse' AND number_of_children > 0;

SELECT marital_status, number_of_children
FROM marital_status
WHERE marital_status = 'Never-married';

SELECT income
FROM income
WHERE income > 50000;
